// @kern-source: adapter-helpers:261
export function resolveAgentArgs(engine: EngineDefinition, permissionLevel: 'full'|'plan'|'read-only'): EngineModeConfig|null {
  if (permissionLevel === 'read-only') return null;
  if (!engine.agent) return null;
  if (permissionLevel === 'full') return engine.agent;
  // plan mode: swap vendor-specific flags. agy has no --permission-mode (it
  // silently ignores unknown flags), so its only real restriction is --sandbox;
  // mapping the bypass flag to a Claude-only flag would leave agy unrestricted.
  const planArgs = engine.agent.args.map((arg: string) => {
    if (arg === '--dangerously-skip-permissions') return engine.id === 'agy' ? '--sandbox' : '--permission-mode=plan';
    if (arg === '--dangerously-bypass-approvals-and-sandbox') return '--sandbox=workspace-write';
    if (arg === 'yolo') return 'plan';
    return arg;
  });
  return { args: planArgs };
}

/**
 * Extract text content from Claude stream-json NDJSON output. Returns plain text with system/hook messages removed.
 */
// @kern-source: adapter-helpers:278
export function stripStreamJson(stdout: string): string {
  const lines = stdout.split('\n');
  const textParts: string[] = [];

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    try {
      const msg = JSON.parse(trimmed);
      // assistant message → extract text blocks
      if (msg.type === 'assistant' && msg.message?.content) {
        for (const block of msg.message.content) {
          if (block.type === 'text' && block.text) textParts.push(block.text);
        }
      }
      // result → extract result text
      else if (msg.type === 'result' && msg.result && !msg.is_error) {
        textParts.push(typeof msg.result === 'string' ? msg.result : JSON.stringify(msg.result));
      }
      // system, hook, etc. → skip
    } catch {
      // Not JSON — raw text from non-Claude engines, keep as-is
      textParts.push(trimmed);
    }
  }

  return textParts.join('\n');
}

