/**
 * Drive interactive `claude` under a pty so the subscription billing path is used. Lazy-imports @kernlang/agon-engines — runs a python3 daemon (kern_engines.cli.daemon) over stdio JSON-RPC, no native node deps. cwd is plumbed through so worktree dispatches land in the right repo; systemPrompt is prepended to the prompt; extraArgv (model/effort launch flags) is forwarded to the engine exec. When AGON_CLAUDE_ANSWER_CHANNEL=file and mode is exec OR agent, claude is asked to Write its answer to a temp file we read as the AUTHORITATIVE result (clean — no TUI scrape), falling back to the scrape if the file is absent. Never throws — returns unavailable:true on any unexpected failure so kern callers can fall through to legacy paths with a simple !result.unavailable check.
 */
// @kern-source: adapter-helpers:393
export async function runClaudePtyDispatch(prompt: string, timeoutSec: number, signal?: AbortSignal, mode?: 'exec'|'agent', cwd?: string, systemPrompt?: string, env?: Record<string,string>, extraArgv?: string[]): Promise<{exitCode:number,stdout:string,stderr:string,durationMs:number,timedOut:boolean,unavailable?:boolean}> {
  const start = Date.now();
  try {
    let mod: any;
    try {
      mod = await import('@kernlang/agon-engines/cli/claude.js' as any);
    } catch (e) {
      return {
        exitCode: 1,
        stdout: '',
        stderr: `pty path unavailable: ${e instanceof Error ? e.message : String(e)}`,
        durationMs: Date.now() - start,
        timedOut: false,
        unavailable: true,
      };
    }

    let session: any;
    try {
      session = await mod.ClaudeCliSession.spawn({
        mode: mode ?? 'exec',
        cwd: cwd,
        env: env,
        extraArgv: extraArgv,
      });
    } catch (e) {
      return {
        exitCode: 1,
        stdout: '',
        stderr: `pty path spawn failed: ${e instanceof Error ? e.message : String(e)}`,
        durationMs: Date.now() - start,
        timedOut: false,
        unavailable: true,
      };
    }

    const onAbort = () => { session.close().catch(() => undefined); };
    if (signal) {
      if (signal.aborted) {
        await session.close().catch(() => undefined);
        return { exitCode: 130, stdout: '', stderr: 'aborted', durationMs: Date.now() - start, timedOut: false };
      }
      signal.addEventListener('abort', onAbort, { once: true });
    }

    // File answer-channel: for one-shot exec (council/forge/brainstorm/tribunal
    // members) AND agent (forge one-shot agent dispatch). claude writes its answer
    // to a temp file we read as authoritative, bypassing the flaky scrape.
    const useFileChannel = useFileChannelForMode(mode);
    let channelDir = '';
    try {
      let composed = composeClaudePtyPrompt(prompt, systemPrompt);
      let answerFile = '';
      if (useFileChannel) {
        const ch = setupFileAnswerChannel(composed);
        composed = ch.prompt; answerFile = ch.answerFile; channelDir = ch.dir;
      }
      const scraped = await session.ask(composed, timeoutSec * 1000);
      // Prefer the authoritative channel file; fall back to the scrape if claude
      // didn't deliver (it sometimes won't) so we never regress to empty.
      const channelText = useFileChannel ? readAnswerChannelFile(answerFile) : '';
      if (useFileChannel && process.env.AGON_DEBUG) console.error(`[agon] answer-channel(file): ${channelText ? 'hit ' + channelText.length + 'ch' : 'miss → scrape fallback'}`);
      const text = channelText || scraped;
      return {
        exitCode: 0,
        stdout: text,
        stderr: channelText ? '' : (useFileChannel ? 'answer-channel: file empty, used scrape fallback' : ''),
        durationMs: Date.now() - start,
        timedOut: false,
      };
    } catch (e: any) {
      const isTimeout = e?.kind === 'timeout' || e?.name === 'ClaudeSessionTimeout';
      // Even on a hard timeout, claude may have already written the channel file
      // before the TUI wedged — salvage it rather than returning empty.
      if (useFileChannel && channelDir) {
        const salvaged = readAnswerChannelFile(join(channelDir, 'answer.md'));
        if (salvaged) {
          return { exitCode: 0, stdout: salvaged, stderr: 'answer-channel: salvaged from file after ask error', durationMs: Date.now() - start, timedOut: false };
        }
      }
      return {
        exitCode: isTimeout ? 124 : 1,
        stdout: '',
        stderr: e instanceof Error ? e.message : String(e),
        durationMs: Date.now() - start,
        timedOut: isTimeout,
      };
    } finally {
      if (signal) signal.removeEventListener('abort', onAbort);
      await session.close().catch(() => undefined);
      if (channelDir) { try { rmSync(channelDir, { recursive: true, force: true }); } catch { /* best-effort */ } }
    }
  } catch (e: any) {
    // Last-ditch: any unforeseen error becomes unavailable so the KERN
    // caller's `!result.unavailable` fall-through still works.
    return {
      exitCode: 1,
      stdout: '',
      stderr: `pty path internal error: ${e instanceof Error ? e.message : String(e)}`,
      durationMs: Date.now() - start,
      timedOut: false,
      unavailable: true,
    };
  }
}

/**
 * Streaming variant of runClaudePtyDispatch — yields response deltas as they arrive, returns the final DispatchResult. extraArgv (model/effort launch flags) is forwarded to the engine exec. Never throws — any unforeseen error returns unavailable:true via the generator's return value, so kern callers can fall through to legacy paths.
 */
export async function* runClaudePtyStreamDispatch(prompt: string, timeoutSec: number, signal?: AbortSignal, mode?: 'exec'|'agent', cwd?: string, systemPrompt?: string, env?: Record<string,string>, extraArgv?: string[]): AsyncGenerator<string, {exitCode:number,stdout:string,stderr:string,durationMs:number,timedOut:boolean,unavailable?:boolean}, void> {
  const start = Date.now();
  let session: any;
  try {
    let mod: any;
    try {
      mod = await import('@kernlang/agon-engines/cli/claude.js' as any);
    } catch (e) {
      return {
        exitCode: 1,
        stdout: '',
        stderr: `pty path unavailable: ${e instanceof Error ? e.message : String(e)}`,
        durationMs: Date.now() - start,
        timedOut: false,
        unavailable: true,
      };
    }

    try {
      session = await mod.ClaudeCliSession.spawn({
        mode: mode ?? 'exec',
        cwd: cwd,
        env: env,
        extraArgv: extraArgv,
      });
    } catch (e) {
      return {
        exitCode: 1,
        stdout: '',
        stderr: `pty path spawn failed: ${e instanceof Error ? e.message : String(e)}`,
        durationMs: Date.now() - start,
        timedOut: false,
        unavailable: true,
      };
    }

    const onAbort = () => { session.close().catch(() => undefined); };
    if (signal) {
      if (signal.aborted) {
        await session.close().catch(() => undefined);
        return { exitCode: 130, stdout: '', stderr: 'aborted', durationMs: Date.now() - start, timedOut: false };
      }
      signal.addEventListener('abort', onAbort, { once: true });
    }

    // File answer-channel (one-shot exec AND agent): stream the scraped deltas for
    // live UX, but read the FINAL answer from the authoritative file claude writes.
    const useFileChannel = useFileChannelForMode(mode);
    let channelDir = '';
    const collected: string[] = [];
    try {
      let composed = composeClaudePtyPrompt(prompt, systemPrompt);
      let answerFile = '';
      if (useFileChannel) {
        const ch = setupFileAnswerChannel(composed);
        composed = ch.prompt; answerFile = ch.answerFile; channelDir = ch.dir;
      }
      const gen = session.askStream(composed, timeoutSec * 1000);
      while (true) {
        const next = await gen.next();
        if (next.done) {
          const scraped = typeof next.value === 'string' && next.value
            ? next.value
            : collected.join('');
          const channelText = useFileChannel ? readAnswerChannelFile(answerFile) : '';
          if (useFileChannel && process.env.AGON_DEBUG) console.error(`[agon] answer-channel(file): ${channelText ? 'hit ' + channelText.length + 'ch' : 'miss → scrape fallback'}`);
          return {
            exitCode: 0,
            stdout: channelText || scraped,
            stderr: channelText ? '' : (useFileChannel ? 'answer-channel: file empty, used scrape fallback' : ''),
            durationMs: Date.now() - start,
            timedOut: false,
          };
        }
        collected.push(next.value);
        yield next.value;
      }
    } catch (e: any) {
      const isTimeout = e?.kind === 'timeout' || e?.name === 'ClaudeSessionTimeout';
      const salvaged = (useFileChannel && channelDir) ? readAnswerChannelFile(join(channelDir, 'answer.md')) : '';
      if (salvaged) {
        return { exitCode: 0, stdout: salvaged, stderr: 'answer-channel: salvaged from file after ask error', durationMs: Date.now() - start, timedOut: false };
      }
      return {
        exitCode: isTimeout ? 124 : 1,
        stdout: collected.join(''),
        stderr: e instanceof Error ? e.message : String(e),
        durationMs: Date.now() - start,
        timedOut: isTimeout,
      };
    } finally {
      if (signal) signal.removeEventListener('abort', onAbort);
      await session.close().catch(() => undefined);
      if (channelDir) { try { rmSync(channelDir, { recursive: true, force: true }); } catch { /* best-effort */ } }
    }
  } catch (e: any) {
    // Outer guard for anything the inner blocks miss.
    try { if (session) await session.close(); } catch { /* ignore */ }
    return {
      exitCode: 1,
      stdout: '',
      stderr: `pty path internal error: ${e instanceof Error ? e.message : String(e)}`,
      durationMs: Date.now() - start,
      timedOut: false,
      unavailable: true,
    };
  }
}
